class SAMLResponseParser:
    """Parses and validates SAML responses from an Identity Provider."""

    def __init__(self, saml_response_b64):
        self.raw_response = base64.b64decode(saml_response_b64)
        self.xml_string = self.raw_response.decode('utf-8')
        self.root = ET.fromstring(self.xml_string)
        self.ns = SAML_NAMESPACES
        self.errors = []

    def validate_response_status(self):
        """Check that the SAML response status is Success."""
        status_code = self.root.find(
            './/samlp:Status/samlp:StatusCode', self.ns
        )
        if status_code is None:
            self.errors.append('No StatusCode element found in SAML response.')
            return False

        status_value = status_code.get('Value', '')
        if 'Success' not in status_value:
            status_message = self.root.find(
                './/samlp:Status/samlp:StatusMessage', self.ns
            )
            msg = status_message.text if status_message is not None else 'Unknown error'
            self.errors.append(f'SAML response status is not Success: {status_value}. Message: {msg}')
            return False

        return True

    def get_assertion(self):
        """Extract the Assertion element from the response."""
        assertion = self.root.find('.//saml:Assertion', self.ns)
        if assertion is None:
            self.errors.append('No Assertion element found in SAML response.')
            return None
        return assertion

    def validate_assertion_conditions(self, assertion):
        """Validate time-based conditions on the assertion."""
        conditions = assertion.find('.//saml:Conditions', self.ns)
        if conditions is None:
            self.errors.append('No Conditions element found in assertion.')
            return False

        now = datetime.utcnow()

        not_before = conditions.get('NotBefore')
        if not_before:
            not_before_dt = self._parse_saml_datetime(not_before)
            if not_before_dt and now < not_before_dt - timedelta(minutes=5):
                self.errors.append(
                    f'Assertion is not yet valid. NotBefore: {not_before}, Now: {now.isoformat()}'
                )
                return False

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            not_on_or_after_dt = self._parse_saml_datetime(not_on_or_after)
            if not_on_or_after_dt and now >= not_on_or_after_dt + timedelta(minutes=5):
                self.errors.append(
                    f'Assertion has expired. NotOnOrAfter: {not_on_or_after}, Now: {now.isoformat()}'
                )
                return False

        # Validate audience restriction
        audience_restriction = conditions.find('.//saml:AudienceRestriction/saml:Audience', self.ns)
        if audience_restriction is not None:
            audience = audience_restriction.text
            if audience and audience != SAML_CONFIG['sp_entity_id']:
                self.errors.append(
                    f'Audience mismatch. Expected: {SAML_CONFIG["sp_entity_id"]}, Got: {audience}'
                )
                return False

        return True

    def validate_assertion_issuer(self, assertion):
        """Validate the issuer of the assertion matches the expected IdP."""
        issuer = assertion.find('saml:Issuer', self.ns)
        if issuer is None:
            self.errors.append('No Issuer element found in assertion.')
            return False

        if issuer.text != SAML_CONFIG['idp_entity_id']:
            self.errors.append(
                f'Issuer mismatch. Expected: {SAML_CONFIG["idp_entity_id"]}, Got: {issuer.text}'
            )
            return False

        return True

    def validate_destination(self):
        """Validate that the response Destination matches our ACS URL."""
        destination = self.root.get('Destination')
        if destination and destination != SAML_CONFIG['sp_acs_url']:
            self.errors.append(
                f'Destination mismatch. Expected: {SAML_CONFIG["sp_acs_url"]}, Got: {destination}'
            )
            return False
        return True

    def validate_in_response_to(self, expected_request_id=None):
        """Validate InResponseTo attribute if we have a stored request ID."""
        in_response_to = self.root.get('InResponseTo')
        if expected_request_id and in_response_to:
            if in_response_to != expected_request_id:
                self.errors.append(
                    f'InResponseTo mismatch. Expected: {expected_request_id}, Got: {in_response_to}'
                )
                return False
        return True

    def extract_name_id(self, assertion):
        """Extract the NameID (primary user identifier) from the assertion."""
        subject = assertion.find('.//saml:Subject/saml:NameID', self.ns)
        if subject is None:
            self.errors.append('No NameID element found in assertion Subject.')
            return None

        name_id_data = {
            'value': subject.text,
            'format': subject.get('Format', ''),
            'sp_name_qualifier': subject.get('SPNameQualifier', ''),
            'name_qualifier': subject.get('NameQualifier', ''),
        }
        return name_id_data

    def extract_attributes(self, assertion):
        """Extract user attributes from the assertion's AttributeStatement."""
        attributes = {}
        attribute_statement = assertion.find('.//saml:AttributeStatement', self.ns)

        if attribute_statement is None:
            return attributes

        for attribute in attribute_statement.findall('saml:Attribute', self.ns):
            attr_name = attribute.get('Name', '')
            attr_friendly_name = attribute.get('FriendlyName', '')

            values = []
            for attr_value in attribute.findall('saml:AttributeValue', self.ns):
                if attr_value.text:
                    values.append(attr_value.text)

            # Use friendly name as key if available, otherwise use the full name
            key = attr_friendly_name if attr_friendly_name else attr_name

            # Store single values as strings, multiple as lists
            if len(values) == 1:
                attributes[key] = values[0]
            elif len(values) > 1:
                attributes[key] = values
            else:
                attributes[key] = None

            # Also store by full OID/URI name for exact lookup
            if attr_name and attr_name != key:
                if len(values) == 1:
                    attributes[attr_name] = values[0]
                elif len(values) > 1:
                    attributes[attr_name] = values
                else:
                    attributes[attr_name] = None

        return attributes

    def extract_session_index(self, assertion):
        """Extract the SessionIndex from AuthnStatement for SLO support."""
        authn_statement = assertion.find('.//saml:AuthnStatement', self.ns)
        if authn_statement is not None:
            return authn_statement.get('SessionIndex')
        return None

    def extract_authn_context(self, assertion):
        """Extract the authentication context class reference."""
        authn_context = assertion.find(
            './/saml:AuthnStatement/saml:AuthnContext/saml:AuthnContextClassRef',
            self.ns
        )
        if authn_context is not None:
            return authn_context.text
        return None

    def parse_and_validate(self, expected_request_id=None):
        """Full parsing and validation of the SAML response."""
        result = {
            'is_valid': False,
            'errors': [],
            'name_id': None,
            'attributes': {},
            'session_index': None,
            'authn_context': None,
        }

        # Validate response-level fields
        if not self.validate_response_status():
            result['errors'] = self.errors
            return result

        if not self.validate_destination():
            result['errors'] = self.errors
            return result

        if not self.validate_in_response_to(expected_request_id):
            result['errors'] = self.errors
            return result

        # Get and validate assertion
        assertion = self.get_assertion()
        if assertion is None:
            result['errors'] = self.errors
            return result

        if not self.validate_assertion_issuer(assertion):
            result['errors'] = self.errors
            return result

        if not self.validate_assertion_conditions(assertion):
            result['errors'] = self.errors
            return result

        # Extract user information
        name_id = self.extract_name_id(assertion)
        if name_id is None:
            result['errors'] = self.errors
            return result

        attributes = self.extract_attributes(assertion)
        session_index = self.extract_session_index(assertion)
        authn_context = self.extract_authn_context(assertion)

        result['is_valid'] = True
        result['name_id'] = name_id
        result['attributes'] = attributes
        result['session_index'] = session_index
        result['authn_context'] = authn_context
        result['errors'] = self.errors

        return result

    @staticmethod
    def _parse_saml_datetime(dt_string):
        """Parse a SAML datetime string into a Python datetime object."""
        try:
            # Handle the common SAML datetime format
            dt_string = dt_string.rstrip('Z')
            if '.' in dt_string:
                return datetime.strptime(dt_string, '%Y-%m-%dT%H:%M:%S.%f')
            else:
                return datetime.strptime(dt_string, '%Y-%m-%dT%H:%M:%S')
        except (ValueError, AttributeError):
            return None


class SAMLAuthnRequestBuilder:
    """Builds SAML Authentication Request XML."""

    @staticmethod
    def build_authn_request():
        """Build a SAML AuthnRequest."""
        request_id = f'_id-{uuid.uuid4().hex}'
        issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

        authn_request = (
            f'<samlp:AuthnRequest '
            f'xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" '
            f'xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" '
            f'ID="{request_id}" '
            f'Version="2.0" '
            f'IssueInstant="{issue_instant}" '
            f'Destination="{SAML_CONFIG["idp_sso_url"]}" '
            f'AssertionConsumerServiceURL="{SAML_CONFIG["sp_acs_url"]}" '
            f'ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">'
            f'<saml:Issuer>{SAML_CONFIG["sp_entity_id"]}</saml:Issuer>'
            f'<samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" '
            f'AllowCreate="true"/>'
            f'</samlp:AuthnRequest>'
        )

        return request_id, authn_request


def create_user_session(saml_result):
    """Create a Flask session from validated SAML assertion data."""
    session.permanent = True
    session['saml_authenticated'] = True
    session['saml_name_id'] = saml_result['name_id']['value']
    session['saml_name_id_format'] = saml_result['name_id']['format']
    session['saml_session_index'] = saml_result['session_index']
    session['saml_authn_context'] = saml_result['authn_context']
    session['saml_auth_time'] = datetime.utcnow().isoformat()

    attributes = saml_result['attributes']

    # Map common SAML attributes to session fields
    # Support both friendly names and OID-based attribute names
    attribute_mappings = {
        'email': [
            'email', 'mail', 'emailAddress',
            'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress',
            'urn:oid:0.9.2342.19200300.100.1.3',
        ],
        'first_name': [
            'firstName', 'givenName', 'givenname',
            'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname',
            'urn:oid:2.5.4.42',
        ],
        'last_name': [
            'lastName', 'surname', 'sn',
            'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname',
            'urn:oid:2.5.4.4',
        ],
        'display_name': [
            'displayName', 'cn', 'commonName',
            'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name',
            'urn:oid:2.5.4.3',
        ],
        'groups': [
            'groups', 'memberOf', 'role',
            'http://schemas.xmlsoap.org/claims/Group',
            'http://schemas.microsoft.com/ws/2008/06/identity/claims/groups',
        ],
        'department': [
            'department', 'ou',
            'urn:oid:2.5.4.11',
        ],
        'employee_id': [
            'employeeNumber', 'employeeID',
            'urn:oid:2.16.840.1.113730.3.1.3',
        ],
        'phone': [
            'telephoneNumber', 'phone',
            'urn:oid:2.5.4.20',
        ],
    }

    user_data = {}
    for session_key, possible_attr_names in attribute_mappings.items():
        for attr_name in possible_attr_names:
            if attr_name in attributes and attributes[attr_name]:
                user_data[session_key] = attributes[attr_name]
                break

    # Fall back to NameID for email if not found in attributes
    if 'email' not in user_data:
        name_id_format = saml_result['name_id'].get('format', '')
        if 'emailAddress' in name_id_format or '@' in saml_result['name_id']['value']:
            user_data['email'] = saml_result['name_id']['value']

    session['user'] = user_data
    session['saml_attributes'] = attributes

    return user_data


def login_required(f):
    """Decorator to require SAML authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('saml_authenticated'):
            session['next_url'] = request.url
            return redirect(url_for('saml_login'))
        return f(*args, **kwargs)
    return decorated_function


