@app.route('/saml/login')
def saml_login():
    """Initiate SAML authentication by redirecting to IdP."""
    request_id, authn_request_xml = SAMLAuthnRequestBuilder.build_authn_request()

    # Store request ID in session for InResponseTo validation
    session['saml_request_id'] = request_id

    # Base64 encode the AuthnRequest
    encoded_request = base64.b64encode(authn_request_xml.encode('utf-8')).decode('utf-8')

    # For HTTP-Redirect binding, we'd URL-encode and redirect
    # For HTTP-POST binding, we render a form that auto-submits
    return render_template_string('''
    <!DOCTYPE html>
    <html>
    <head><title>Redirecting to Identity Provider...</title></head>
    <body onload="document.forms[0].submit();">
        <h2>Redirecting to Identity Provider...</h2>
        <form method="POST" action="{{ idp_url }}">
            <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
            <input type="hidden" name="RelayState" value="{{ relay_state }}" />
            <noscript>
                <p>JavaScript is disabled. Click the button below to continue.</p>
                <input type="submit" value="Continue" />
            </noscript>
        </form>
    </body>
    </html>
    ''', idp_url=SAML_CONFIG['idp_sso_url'],
         saml_request=encoded_request,
         relay_state=session.get('next_url', url_for('dashboard')))


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """Assertion Consumer Service - Process SAML response from IdP."""
    saml_response_b64 = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', url_for('dashboard'))

    if not saml_response_b64:
        return jsonify({
            'error': 'No SAMLResponse found in the request.'
        }), 400

    try:
        parser = SAMLResponseParser(saml_response_b64)
    except Exception as e:
        return jsonify({
            'error': f'Failed to parse SAML response: {str(e)}'
        }), 400

    # Validate with stored request ID
    expected_request_id = session.pop('saml_request_id', None)
    result = parser.parse_and_validate(expected_request_id=expected_request_id)

    if not result['is_valid']:
        app.logger.error(f'SAML validation failed: {result["errors"]}')
        return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head><title>Authentication Failed</title></head>
        <body>
            <h1>Authentication Failed</h1>
            <p>There was a problem processing your sign-in.</p>
            <ul>
            {% for error in errors %}
                <li>{{ error }}</li>
            {% endfor %}
            </ul>
            <a href="{{ url_for('saml_login') }}">Try Again</a>
        </body>
        </html>
        ''', errors=result['errors']), 403

    # Create user session from SAML assertion
    user_data = create_user_session(result)

    app.logger.info(
        f'SAML SSO successful for user: {result["name_id"]["value"]} '
        f'(email: {user_data.get("email", "N/A")})'
    )

    # Redirect to the original requested URL or dashboard
    return redirect(relay_state)


@app.route('/saml/sls', methods=['GET', 'POST'])
def saml_sls():
    """Single Logout Service - Process logout request/response from IdP."""
    if request.method == 'POST':
        # Handle LogoutResponse from IdP
        saml_response_b64 = request.form.get('SAMLResponse')
        if saml_response_b64:
            try:
                xml_data = base64.b64decode(saml_response_b64).decode('utf-8')
                root = ET.fromstring(xml_data)
                status_code = root.find(
                    './/samlp:Status/samlp:StatusCode', SAML_NAMESPACES
                )
                if status_code is not None and 'Success' in status_code.get('Value', ''):
                    session.clear()
                    return redirect(url_for('index'))
            except Exception as e:
                app.logger.error(f'Error processing SLS response: {str(e)}')

    session.clear()
    return redirect(url_for('index'))


@app.route('/saml/logout')
@login_required
def saml_logout():
    """Initiate SAML Single Logout."""
    name_id = session.get('saml_name_id', '')
    session_index = session.get('saml_session_index', '')
    request_id = f'_id-{uuid.uuid4().hex}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    logout_request = (
        f'<samlp:LogoutRequest '
        f'xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" '
        f'xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" '
        f'ID="{request_id}" '
        f'Version="2.0" '
        f'IssueInstant="{issue_instant}" '
        f'Destination="{SAML_CONFIG["idp_slo_url"]}">'
        f'<saml:Issuer>{SAML_CONFIG["sp_entity_id"]}</saml:Issuer>'
        f'<saml:NameID>{name_id}</saml:NameID>'
    )

    if session_index:
        logout_request += f'<samlp:SessionIndex>{session_index}</samlp:SessionIndex>'

    logout_request += '</samlp:LogoutRequest>'

    encoded_request = base64.b64encode(logout_request.encode('utf-8')).decode('utf-8')

    # Clear local session
    session.clear()

    return render_template_string('''
    <!DOCTYPE html>
    <html>
    <head><title>Logging out...</title></head>
    <body onload="document.forms[0].submit();">
        <h2>Logging out...</h2>
        <form method="POST" action="{{ idp_slo_url }}">
            <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
            <noscript>
                <p>JavaScript is disabled. Click the button below to continue.</p>
                <input type="submit" value="Continue" />
            </noscript>
        </form>
    </body>
    </html>
    ''', idp_slo_url=SAML_CONFIG['idp_slo_url'], saml_request=encoded_request)


